class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1e9 + 7;
        int n = zero + one;
        vector<vector<long long>> dp(2, vector<long long>(n + 1, 0));
        dp[0][0] = 1;
        dp[1][0] = 1;
        for (int i = 1; i <= n; ++i) {
            dp[0][i] = (dp[0][i - 1] + (i <= limit ? 0 : dp[1][i - 1] - (i - limit - 1 >= 0 ? dp[1][i - limit - 1] : 0))) % MOD;
            dp[1][i] = (dp[1][i - 1] + (i <= limit ? 0 : dp[0][i - 1] - (i - limit - 1 >= 0 ? dp[0][i - limit - 1] : 0))) % MOD;
        }
        return (int)((dp[1][zero] - (zero - limit >= 0 ? dp[1][zero - limit] : 0) + MOD) % MOD);
    }
};
